        // For this example we implement a vectorized approach.
        pipe_.InitBuffer(tmp1_, 1, batchSize_ * hiddenSize_ * sizeof(float)); // pre-activation
        pipe_.InitBuffer(tmp2_, 1, batchSize_ * outputSize_ * sizeof(float));
        pipe_.InitBuffer(weightTileI2h_, 1, tileK_ * tileH_ * sizeof(float));
        pipe_.InitBuffer(weightTileH2o_, 1, tileH_ * tileO_ * sizeof(float));
        // shared buffer for tanh
        pipe_.InitBuffer(sharedTmp_, 1, batchSize_ * hiddenSize_ * sizeof(uint8_t)); // needed by Tanh API
    }

    __aicore__ inline void Process()
    {
        if (totalSteps_ == 0 || batchSize_ == 0) return;

        const uint32_t blockIdx = GetBlockIdx();
        const uint32_t blockNum = GetBlockNum();

        // Each block handles a subset of time steps (grid-stride)
