            uint32_t offsetX = t * batchSize_ * inputSize_;
            DataCopy(xLocal, xGm_[offsetX], batchSize_ * inputSize_);
            inQueueX_.EnQue(xLocal);

            // ---- Matmul i2h: pre = inp @ w_i2h^T + b_i2h ----
            // inp = cat(x[t], h) in concept, but we do matmul directly with two parts:
            // pre = x[t] * (first I columns of w_i2h^T) + h * (last H columns of w_i2h^T) + b_i2h
