            // We'll add bias now: result in tmp1_ is pre = inp*W^T, need to add b_i2h
            Add(tmp1_, tmp1_, bI2hGm_, batchSize_ * hiddenSize_);

            // Tanh activation -> store back to localH_ (new h)
